const useActor = () => {
  const { identity, isAuthenticated } = useCustomAuth();
  const [actor, setActor] = reactExports.useState(null);
  const [isFetching, setIsFetching] = reactExports.useState(false);
  reactExports.useEffect(() => {
    const initActor = async () => {
      if (isAuthenticated && identity) {
        setIsFetching(true);
        try {
          const httpActor = createHttpActor(identity);
          setActor(httpActor);
        } catch (e) {
          console.error("Error creating actor", e);
        } finally {
          setIsFetching(false);
        }
      } else {
        setActor(null);
      }
    };
    initActor();
  }, [identity, isAuthenticated]);
  return { actor, isFetching };
};
